import requests

def test_manager_views_team_invalid_team_id(api_base_url, manager_token):
    response = requests.get(
        f"{api_base_url}/api/teams/nonexistent-999",
        headers={"Authorization": f"Bearer {manager_token}"}
    )
    assert response.status_code in [400, 404]
    data = response.json()
    assert 'error' in data or 'message' in data

import requests

def test_manager_views_team_missing_mandatory_field(api_base_url, manager_token, corrupted_team_fixture):
    team_id = corrupted_team_fixture['id']
    response = requests.get(
        f"{api_base_url}/api/teams/{team_id}",
        headers={"Authorization": f"Bearer {manager_token}"}
    )
    assert response.status_code in [200, 400]
    if response.status_code == 200:
        data = response.json()
        assert 'name' in data
    else:
        data = response.json()
        assert 'error' in data

import requests

def test_manager_views_team_malformed_authorization_header(api_base_url, team_fixture):
    team_id = team_fixture['id']
    response = requests.get(
        f"{api_base_url}/api/teams/{team_id}",
        headers={"Authorization": "Bearer malformed::invalid::token"}
    )
    assert response.status_code == 401
    data = response.json()
    assert 'error' in data
